_shaderData.warp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

        ret = texture(sampler_main, vUv)*.999;

  fragColor = ret;
}

_shaderData.comp:
#version 300 es
precision highp float;

// VisualSynth uniforms
uniform float uTime;
uniform float uFrame;
uniform float uFps;
uniform float uRms;

// Audio uniforms
uniform float audioLow;      // bass
uniform float audioLowSmooth; // bass_att
uniform float audioMid;      // mid
uniform float audioMidSmooth; // mid_att
uniform float audioHigh;     // treb
uniform float audioHighSmooth; // treb_att

// Screen uniforms
uniform float uAspectX;
uniform float uAspectY;
uniform vec2 uAspect;
uniform vec2 uTexSize;

// Random values
uniform vec2 uRandomPreset;
uniform vec2 uRandomFrame;

// Input from vertex shader
in vec2 vUv;
in float vRadius;
in float vAngle;

// Output
out vec4 fragColor;

// Textures
uniform sampler2D sampler_main;
uniform sampler2D sampler_noise_lq;
uniform sampler2D sampler_noise_mq;
uniform sampler2D sampler_noise_hq;
uniform sampler2D sampler_blur1;
uniform sampler2D sampler_blur2;
uniform sampler2D sampler_blur3;

// Helper functions
float clamp01(float x) { return clamp(x, 0.0, 1.0); }
vec2 clamp01(vec2 x) { return clamp(x, vec2(0.0), vec2(1.0)); }
vec3 clamp01(vec3 x) { return clamp(x, vec3(0.0), vec3(1.0)); }
vec4 clamp01(vec4 x) { return clamp(x, vec4(0.0), vec4(1.0)); }

// Texture helper functions
vec4 GetPixel(vec2 uv) { return texture(sampler_main, uv); }
vec4 GetBlur1(vec2 uv) { return texture(sampler_blur1, uv); }
vec4 GetBlur2(vec2 uv) { return texture(sampler_blur2, uv); }
vec4 GetBlur3(vec2 uv) { return texture(sampler_blur3, uv); }


void main() {
  vec4 ret = vec4(0.0);
  vec2 uv = vUv;
  float rad = vRadius;

        float cutoff = 100;

        vec2 d1 = vUv - vec2(q1,q2);
        vec2 d2 = vUv - vec2(q3,q4);
        vec2 d3 = vUv - vec2(q5,q6);

        // dot(d1,d1) is in 0...3
        // pot1 is in .33 ... 100
        // at distance 0, pot1 is 100
        // at distance .1, pot1 is 50
        // at distance .05, pot1 is 1/(.0125) = 80
        // at distance .11, pot1 is 1/(.0221) = 45
        // at distance .2, pot is 1/.05 = 20;
        // at distance 1, pot is 1/1.01 ~= 1;
        float pot1 = 1/(dot(d1,d1) + .01);
        float pot2 = 1/(dot(d2,d2) + .01);
        float pot3 = 1/(dot(d3,d3) + .01);

        //          |stacked | center | float  | edge  |      | double | far away
        // ------------------| -------------------------------------------------
        // distance:| 0      | 0      | .05   | .1    | .11  | .2     | 1
        // pot:     | 300    | 100    | 80    | 50    | 45   | 20     | 1
        // z:       | > .1   | .1     | √2/2  |  0    | imaginary
        //

        float pot = pot1 + pot2 + pot3;

        // pot is between 0 and 300
        // when distance is 0 from one and far from the others, pot is 100, z should be .1
        // on boundary, pot is 50, z should be 0

        vec2 texloc = vUv;
        if (pot > 50) {
            float z = (sqrt(pot - 50))/70;

            float wt1 = pot1/pot;
            float wt2 = pot2/pot;
            float wt3 = pot3/pot;

            vec3 d1z = normalize(vec3(d1.x, d1.y, z));
            vec3 d2z = normalize(vec3(d2.x, d2.y, z));
            vec3 d3z = normalize(vec3(d3.x, d3.y, z));
            vec3 n = normalize(d1z*wt1 + d2z*wt2 + d3z*wt3);

            texloc = vUv + .05*n.xy/n.z;
        }
        ret = .5*texture(sampler_fw_main, texloc)+.5*texture(sampler_rand00, texloc);


  fragColor = ret;
}
